export type Todo = { id: string; title: string; completed: boolean };

let db: Database.Database | null = null;

function getDb() {
  if (db) return db;
  const dir = join(process.cwd(), 'data');
  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
  const database = new Database(join(dir, 'todos.sqlite'));
  database.exec(`
    CREATE TABLE IF NOT EXISTS todos (
      id TEXT PRIMARY KEY,
      title TEXT NOT NULL,
      completed INTEGER NOT NULL DEFAULT 0
    )
  `);
  db = database;
  return database;
}

export function getAllTodos(): Todo[] {
  const rows = getDb().prepare('SELECT id, title, completed FROM todos ORDER BY id').all() as any[];
  return rows.map(r => ({ id: r.id, title: r.title, completed: !!r.completed }));
}

export function insertTodo(id: string, title: string): Todo {
  getDb().prepare('INSERT INTO todos (id, title, completed) VALUES (?, ?, 0)').run(id, title);
  return { id, title, completed: false };
}

export function toggleTodo(id: string): Todo | null {
  const row = getDb().prepare('SELECT id, title, completed FROM todos WHERE id = ?').get(id) as any;
  if (!row) return null;
  const next = row.completed ? 0 : 1;
  getDb().prepare('UPDATE todos SET completed = ? WHERE id = ?').run(next, id);
  return { id: row.id, title: row.title, completed: !!next };
}

export function deleteTodo(id: string): boolean {
  const res = getDb().prepare('DELETE FROM todos WHERE id = ?').run(id);
  return res.changes > 0;
}
